"""
MKT Christ Commentary — Psalms chapters 18–21
Run: python3 scripts/zc-christ-psalms-18-21.py

Key decisions:
- Ps 18: v2 'horn of salvation' → Luke 1:69 (Zechariah applies to Christ);
  vv4-5 death/Sheol grip → Acts 2:24 (impossible for death to hold Christ);
  v49 direct NT citation → Rom 15:9 (Paul applies to Christ's Gentile praise);
  v50 'to David and his descendants forever' → covenant fulfilled in Christ (Acts 2:30)
- Ps 19: v4 'proclamation goes out through all the earth' → Rom 10:18 (Paul applies
  to gospel spread); v14 gōʾēl (redeemer) → Christological kinsman-redeemer title
- Ps 20: v6 'LORD saves his anointed (mĕšîḥô)' → messianic title; resurrection as the
  divine answer from heaven; vv6-7 divine-power-not-chariots → 1 Cor 1:18 cross
- Ps 21: v4 'length of days forever and ever' → resurrection/eternal life;
  v6 'gladness in your presence' → Heb 12:2 (joy set before Christ);
  vv8-12 judgment on enemies → 1 Cor 15:25-26 eschatological enemy-subjection
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "18": {
    "1": '<p>A theme: Psalm 18 is paired almost verbatim with 2 Samuel 22, where it is explicitly attributed to David "when the LORD rescued him from all his enemies and from Saul." The superscription "David the servant of the LORD" is the covenant title par excellence — the same title applied to the Suffering Servant of Isaiah 53. The opening declaration "I love you, LORD, my strength" grounds the entire psalm in covenant affection, anticipating Christ\'s total love for the Father that drives his obedience through death.</p>',
    "2": '<p>A direct connection: "The LORD is my rock, my fortress... the horn of my salvation." The accumulated military-protection titles reach their Christological fulfillment when Zechariah applies "a horn of salvation" (<em>keras sōtērias</em> / <em>qeren yĕšûʿāh</em>) to Jesus in Luke 1:69: "He has raised up a horn of salvation for us in the house of his servant David." What David confesses as experienced protection is fulfilled in Christ as the definitive agent of salvation — the horn that cannot be broken off.</p>',
    "3": '<p>A theme: "I called to the LORD, who is worthy of all praise, and I am saved from my enemies." The pattern of calling → hearing → saving defines the entire psalm\'s movement. For Christ, this pattern is realized in Gethsemane and the resurrection: Hebrews 5:7 says Christ "offered up prayers and petitions with fervent cries and tears to the one who could save him from death, and he was heard because of his reverent submission." The one who cries is heard and saved.</p>',
    "4": '<p>A shadow: "The cords of death wrapped around me; the floods of chaos overwhelmed me." The death-grip imagery describes the king\'s extremity. Acts 2:24 states that God "raised him up, loosing the pangs of death (<em>lysas tas ōdinas tou thanatou</em>), because it was not possible for him to be held by it" — the "cords" of Sheol could not hold the Messiah. The psalm\'s imagery of being overwhelmed by death\'s floods becomes the theological vocabulary for understanding the resurrection as loosing of death\'s grip.</p>',
    "5": '<p>A shadow: "The ropes of Sheol entangled me; the snares of death were set before me." The descent toward Sheol — the underworld\'s ropes and snares — frames the speaker\'s situation as near-death. Peter\'s Pentecost sermon (Acts 2:24–27) connects the loosing of death\'s bonds directly to Psalm 16:10 ("you will not abandon me to Sheol"), but the imagery of Sheol\'s ropes entangling the one who cannot be held runs through the whole cluster of Psalms 16, 18, and 22 as the Passion\'s OT framework.</p>',
    "6": '<p>A theme: "From his temple he heard my voice, and my cry before him came into his ears." The prayer heard in heaven establishes the pattern of effective intercession — the king\'s cry reaches the divine throne directly. For Christ, this reaches its fullness in the high-priestly intercession: Hebrews 7:25 ("he always lives to make intercession for them") and John 17 (the great prayer heard in heaven). The cry ascending and the divine answer descending is the Christological shape of prayer.</p>',
    "7": '<p>A shadow: "The earth shook and trembled; the foundations of the mountains quaked and shook, for he was angry." The cosmic theophany — creation shuddering at divine wrath — is the imagery of divine judgment. Matthew 27:51 records that at Christ\'s death "the earth shook and the rocks split" — the theophany language of Psalm 18 materializes at the cross, as the divine wrath that the king\'s enemies had provoked fell upon the king himself.</p>',
    "8": '<p>A shadow: "Smoke poured from his nostrils and consuming fire from his mouth; blazing coals ignited before him." The divine warrior\'s theophanic fire is the imagery of holy wrath expressed in creation\'s elements. The NT sees divine wrath as both revealed at the cross (where Christ bore it) and reserved for the final judgment (2 Thess 1:7–8: "in blazing fire with his powerful angels... inflicting vengeance"). The theophany of Ps 18 bridges both: wrath absorbed at the cross and wrath dispensed at the end.</p>',
    "9": '<p>A shadow: "He bowed the heavens and came down; dark cloud was under his feet." The divine descent — heaven bending toward earth — is the great theophanic act that the Psalter uses for YHWH\'s saving intervention. The ultimate fulfillment is the Incarnation itself: John 1:14 ("the Word became flesh and dwelt among us") and Philippians 2:7–8 ("emptied himself, taking the form of a servant... he humbled himself"). God descending to earth is not merely imagery; in Christ it became literal history.</p>',
    "10": '<p>A shadow: "He mounted a cherub and flew; he soared on the wings of the wind." The divine warrior riding the cherubim is the imagery of YHWH enthroned above the ark of the covenant (Ps 80:1; 99:1) and of the heavenly chariot-throne of Ezekiel 1. The Christological fulfillment appears in Revelation 19:11 (Christ riding on a white horse as the divine warrior) and in the ascension (Acts 1:9–11: Christ taken up into a cloud) — the same heavenly-chariot imagery now applied to the risen Christ.</p>',
    "11": '<p>A shadow: "He made darkness his shelter, his canopy of dark clouds heavy with rain." The divine concealment in darkness is the mystery of the theophany — God hidden within the storm that is also his vehicle of approach. At Golgotha, Matthew 27:45 records: "From noon until three in the afternoon darkness came over all the land." The darkness of the cross is the dark cloud of Psalm 18 — the theophanic concealment of the divine within the suffering of the Messiah.</p>',
    "12": '<p>A shadow: "From the brightness of his presence his clouds burst forth with hailstones and coals of fire." The double movement of the theophany — concealment in darkness (v. 11) and explosion of light through the darkness — mirrors the cross-to-resurrection movement: the concealment of God in Christ\'s death, and the burst of divine glory in the resurrection. Revelation 15:8 ("the temple was filled with smoke from the glory of God") and 21:23 ("the glory of God gives it light") both draw on this theophanic vocabulary.</p>',
    "13": '<p>A shadow: "The LORD thundered from heaven; the Most High raised his voice amid hailstones and coals of fire." The divine voice from heaven is the theophanic speech. Three times in the Gospels a voice speaks from heaven to or about Jesus: at the baptism (Matt 3:17), the transfiguration (Matt 17:5), and in John 12:28–29 (the crowd said "it thundered"). The theophanic voice of Psalm 18 is actualized in the divine voice that authorizes Jesus\'s identity at each decisive moment of his ministry.</p>',
    "14": '<p>A shadow: "He shot his arrows and scattered them; he hurled lightning bolts and threw them into confusion." The divine warrior scattering enemies through weapons of the storm is the imagery of Exodus 14 (the pillar of fire confusing the Egyptians) and of Revelation 8–9 (the trumpet judgments). Christ\'s final conquest of his enemies is described in Revelation 19:15 ("Out of his mouth comes a sharp sword with which to strike down the nations") — the divine warrior\'s weapons now the word of the triumphant Christ.</p>',
    "15": '<p>A shadow: "The channels of the sea were exposed and the foundations of the world were laid bare at your rebuke, O LORD, at the blast of the breath of your nostrils." The Exodus imagery (the Reed Sea parted by the wind of God\'s nostrils, Exod 14:21; 15:8) recapitulated in cosmic scale. Christ\'s rebuke of the storm (Mark 4:39: "Quiet! Be still!") and the calming of the sea demonstrate that the one who does what only YHWH does (rebuking chaos waters) is present in Jesus.</p>',
    "16": '<p>A shadow: "He reached down from on high and took hold of me; he pulled me out of deep waters." The divine arm reaching down from heaven to rescue is the salvation-imagery of the Exodus and of every rescue in the Psalter. In Christ, this becomes literal in the Incarnation: the divine arm reaches down not merely to rescue from above but to enter the deep waters of humanity — Hebrews 2:14-17: "he shared in their humanity... to help Abraham\'s descendants."</p>',
    "17": '<p>A theme: "He rescued me from my powerful enemy... for they were stronger than I was." The divine rescue from enemies who were humanly overwhelming is the pattern of Christus Victor — Christ\'s victory over the powers of sin, death, and evil that were genuinely stronger than any unaided human. Colossians 2:15: "Having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross." The enemies stronger than any human were defeated by the divine power working through the human Messiah.</p>',
    "18": '<p>A theme: "They confronted me in the day of my disaster, but the LORD was my support." The opposition at the moment of extremity and the divine upholding — this is the Gethsemane-and-cross pattern. Luke 22:43: "An angel from heaven appeared to him and strengthened him" — divine support in the hour of confrontation. The "day of disaster (<em>yôm ʾêdî</em>)" is the hour of the Passion; the divine support is the Father\'s sustaining presence even in the cry of dereliction (Ps 22:1).</p>',
    "19": '<p>A theme: "He brought me out into an open place; he rescued me, because he was pleased with me." The spacious rescue after confinement is the resurrection imagery: from the tomb\'s confinement to the open world of the new creation. "Because he was pleased with me (<em>kî ḥāpeṣ bî</em>)" — the divine delight in the rescued one parallels Matthew 3:17 ("This is my Son, whom I love; with him I am well pleased") — the Father\'s stated delight in the Son grounds the Resurrection as the Father\'s vindication of the one with whom he is pleased.</p>',
    "20": '<p>A type: "The LORD rewarded me according to my righteousness; he repaid me according to the cleanness of my hands." The king\'s righteousness as the ground of vindication is, in the human David, aspirational (cf. 1 Kgs 11:4 — Solomon\'s heart was not fully devoted). In Christ alone is this righteousness fully and literally true: 2 Corinthians 5:21 ("he who had no sin") and 1 Peter 2:22 ("he committed no sin"). The vindication the Davidic king experienced in type, Christ receives in reality.</p>',
    "21": '<p>A type: "For I have kept to the LORD\'s ways and have not turned away from my God in rebellion." The claim of covenant fidelity that is relatively true of David and his better successors becomes absolutely true only in Christ — the one who "was tempted in every way, just as we are — yet he did not sin" (Heb 4:15). Every verse of vv. 20–24 that claims royal righteousness is a type pointing beyond every imperfect Davidic king to the one whose righteousness is perfect.</p>',
    "22": '<p>A type: "All his rules were set before me, and I did not set aside his statutes." The Torah-fidelity of the king is the covenant requirement (Deut 17:18-20: the king must copy and read the Torah all his life). The NT presents Christ as the Torah\'s perfect fulfillment and embodiment: Matthew 5:17 ("I have not come to abolish the Law or the Prophets but to fulfill them"). Christ did not set aside a single statute — he fulfilled the Torah from within.</p>',
    "23": '<p>A type: "I was blameless before him and kept myself from wrongdoing." The claim of blamelessness (<em>tāmîm</em>) is the term used for the unblemished sacrifice — the same standard required for the Passover lamb (Exod 12:5) and the Levitical offerings (Lev 22:19-21). Christ is the sacrifice that is literally <em>tāmîm</em> — blameless, unblemished. 1 Peter 1:19 applies exactly this imagery: "as of a lamb without blemish or defect" (<em>amōmou kai aspilou</em>).</p>',
    "24": '<p>A type: "So the LORD rewarded me according to my righteousness, according to the cleanness of my hands in his eyes." The divine reward of righteousness completes the type: the Resurrection is the Father\'s "reward" to the perfectly righteous Son. Romans 1:4 frames the resurrection as the declaration of Christ\'s divine Sonship "with power." The vindication of the righteous king in Psalm 18 is fulfilled when the perfectly righteous one is raised from the dead.</p>',
    "25": '<p>A revelation of God: "To the faithful you show yourself faithful; to the blameless you show yourself blameless." The divine reciprocity principle — God reflects back the character of those who approach him — is not merely moral instruction but a revelation of God\'s character. Christ as the perfection of faithfulness and blamelessness receives the fullness of divine faithfulness in return: the resurrection is the Father showing himself perfectly faithful to the perfectly faithful Son.</p>',
    "26": '<p>A revelation of God: "To the pure you show yourself pure; but to the devious you show yourself cunning." The divine responsiveness — showing wisdom-in-judgment to the devious (frustrating their plans by their own devices) — anticipates the cross: the devious plans of those who crucified Christ were turned by divine wisdom into the means of salvation (1 Cor 2:8: "None of the rulers of this age understood it, for if they had, they would not have crucified the Lord of glory").</p>',
    "27": '<p>A revelation of God: "For you save an afflicted people, but proud eyes you humble." The pattern of divine reversal — salvation for the lowly, humbling for the proud — is the Magnificat logic (Luke 1:51-52: "he has scattered those who are proud... but has lifted up the humble"). Christ himself embodies this reversal: "whoever exalts himself will be humbled, and whoever humbles himself will be exalted" (Matt 23:12). His own path — humiliation to exaltation — is the paradigmatic enactment of this divine principle.</p>',
    "28": '<p>A revelation of God: "For you light my lamp; the LORD my God brightens my darkness." The divine light in darkness is the redemptive pattern from Genesis 1:3 onward. John 1:5 ("The light shines in the darkness, and the darkness has not overcome it") and John 8:12 ("I am the light of the world") identify Christ as the one who performs what YHWH performs in Psalm 18: he is the lamp that lightens darkness — not merely a recipient of divine light but its embodiment.</p>',
    "29": '<p>A theme: "For by your help I can charge against a raiding party; by my God I can scale a wall." The capacities made possible by divine help — superhuman military achievement through divine empowerment — describe the believer\'s life by divine power. Paul applies this logic to the Christian life in Philippians 4:13 ("I can do all this through him who gives me strength") and 2 Corinthians 12:9-10 ("my power is made perfect in weakness... for when I am weak, then I am strong"). The divine-capacitation pattern is fulfilled in the Spirit-empowered life.</p>',
    "30": '<p>A revelation of God: "This God — his way is perfect; the LORD\'s word is refined and true; he is a shield to all who shelter in him." The perfection of God\'s way is the foundation of all trust. Christ as the Word (<em>Logos</em>) of God — John 1:1, 14 — is the divine Word that is "refined and true": the complete self-expression of the divine character in human form. The one who shelters in the divine Word shelters in Christ, who is that Word made flesh.</p>',
    "31": '<p>A revelation of God: "For who is God besides the LORD? And who is a rock except our God?" The incomparability formula — the unique divine identity — is taken up in the NT and applied to Jesus in a way that identifies him with YHWH. 1 Corinthians 10:4 ("they drank from the spiritual rock that accompanied them, and that rock was Christ") applies the "rock" title to the pre-existent Christ who sustained Israel in the wilderness — the rock of Psalm 18 is Christ.</p>',
    "32": '<p>A theme: "It is God who arms me with strength and makes my way perfect." The divine provision of strength and the perfecting of the path — both achieved through divine action, not human effort — describes Christ\'s path: "made perfect through suffering" (Heb 2:10; 5:9). The <em>teleiōsis</em> (perfection/completion) of Christ in Hebrews is the fulfillment of the Psalter\'s language of YHWH making the king\'s way perfect.</p>',
    "33": '<p>A theme: "He makes my feet like the feet of a deer and sets me securely on the heights." The sure-footedness on dangerous terrain — the deer on mountain crags — is the image of the covenant life lived with divine support. Habakkuk 3:19 repeats this exactly: "The Sovereign LORD is my strength; he makes my feet like the feet of a deer." Christ\'s entire ministry is marked by this sure-footed movement through dangerous opposition — temptation (Matt 4), controversy (Luke 4), the Passion — without stumbling.</p>',
    "34": '<p>A theme: "He trains my hands for battle; my arms can bend a bow of bronze." The divine training of the warrior for battle is the type of Christ\'s preparation for his ministry and passion. Hebrews 5:7-9: "Although he was a son, he learned obedience from what he suffered and, once made perfect, he became the source of eternal salvation." The divine training through suffering that perfects the king for his definitive battle is the Christological shape of Psalm 18\'s warrior imagery.</p>',
    "35": '<p>A type: "You have given me the shield of your salvation; your right hand held me up, and your gentleness made me great." "Your gentleness (<em>ʿănāwātĕkā</em>) made me great" — the divine condescension, the gentle humility of YHWH toward the king, is what exalts him. In Christ, this becomes literal: the divine gentleness is the Incarnation itself, and it produces the greatest exaltation — Philippians 2:8-9: "he humbled himself... therefore God exalted him to the highest place."</p>',
    "36": '<p>A theme: "You gave wide room for my steps beneath me, and my feet did not slip." The divine provision of a wide, non-slipping path is the security of covenant life. Jude 24 applies this to the Christian community under Christ: "to him who is able to keep you from stumbling and to present you before his glorious presence without fault and with great joy." Christ as the one who keeps from stumbling fulfills the divine-keeping of Psalm 18.</p>',
    "37": '<p>A shadow: "I pursued my enemies and overtook them and did not turn back until they were finished." The relentless royal pursuit that does not stop until victory is complete — this is the eschatological imagery of Christ\'s campaign against all opposition. 1 Corinthians 15:25: "he must reign until he has put all his enemies under his feet." The campaign of Psalm 18 is the type of the ongoing Christological campaign that ends only at the last enemy\'s defeat.</p>',
    "38": '<p>A shadow: "I struck them down so that they could not rise; they fell under my feet." The fallen enemies who cannot rise is the type of Christ\'s ultimate defeat of all enemies including death: 1 Corinthians 15:26 ("the last enemy to be destroyed is death") and Revelation 20:14 ("death and Hades were thrown into the lake of fire"). The king\'s enemies who cannot rise anticipate the enemies of Christ who will be subjected — finally and permanently — under his feet.</p>',
    "39": '<p>A shadow: "For you armed me with strength for the battle; you brought down under me those who rose against me." The divine arming for battle and the subjection of the opposition is the pattern of Christ\'s victory over sin and death. Ephesians 6:10-17 applies the divine-arming imagery to the Christian life under Christ: the armor of God is now available through the victory Christ won. Those who rose against the Messiah — sin, death, the powers — are brought down under him.</p>',
    "40": '<p>A shadow: "You made my enemies turn their backs in retreat, and I destroyed those who hated me." The rout of the enemies who hate the anointed king is the type of the eschatological defeat of those opposed to Christ. The NT consistently frames the present age as the time of Christ\'s ongoing victory (Col 2:15; Eph 1:21-22; Rev 19:11-21). The routing of Psalm 18 is the Christological campaign whose completion is guaranteed but whose full execution awaits the Parousia.</p>',
    "41": '<p>A shadow: "They cried for help, but there was no one to save them — they even cried to the LORD, but he did not answer them." The unanswered prayer of those who oppose the anointed king is a sobering element of the Royal Psalms. In the eschatological context, it anticipates Matthew 7:23 ("I never knew you. Away from me, you evildoers!") and Luke 13:25-27 (the closed door). The cry that is not answered is the cry of those who rejected the Messianic king\'s mediation when it was offered.</p>',
    "42": '<p>A shadow: "I ground them fine as windblown dust; I threw them out like mud from the streets." The complete defeat of enemies — ground to dust, cast out — is the type of final judgment. The imagery of dust connects to Genesis 3:19 (the curse of death: "you are dust, and to dust you will return") and to Daniel 2:35 (the statue ground to dust by the stone not cut by human hands — the Messianic kingdom). Final judgment reduces all opposition to what death already made humanity: dust.</p>',
    "43": '<p>A direct connection: "You saved me from conflicts with my own people; you made me head of the nations; people I had not known served me." The Davidic king as head of the nations who were unknown to him — this is the Gentile mission. Paul cites Psalm 18:49 (next verse) in the context of Christ\'s Gentile mission (Rom 15:9), making Psalm 18:43 the Christological grounding for the universal mission: Christ is made "head of the nations" in a way that exceeds David, encompassing all peoples (Eph 1:22).</p>',
    "44": '<p>A shadow: "As soon as they heard of me, they obeyed; foreigners submitted to me." The submission of the nations upon hearing — the proclamation that produces obedience — is the pattern of the apostolic mission. Romans 10:14-17: "How can they believe in the one of whom they have not heard? And how can they hear without someone preaching to them?" The "hearing" that produces obedience in Psalm 18:44 is the hearing of the gospel in the nations.</p>',
    "45": '<p>A shadow: "Foreigners lost their courage and came out of their fortresses trembling." The trembling submission of the nations to the Davidic king — their strongholds no longer holding them — is the type of the eschatological submission of all things to Christ (Phil 2:10-11: "every knee should bow, in heaven and on earth and under the earth, and every tongue acknowledge that Jesus Christ is Lord"). The fortress-capitulation of Psalm 18 anticipates the universal submission of the Parousia.</p>',
    "46": '<p>A revelation of God: "The LORD lives! Blessed be my Rock! Exalted be the God of my salvation!" The doxology of the living God who saves — "The LORD lives (<em>ḥay YHWH</em>)!" — is the OT oath formula asserting YHWH\'s active, living reality over against dead idols (1 Kgs 17:1; 18:10, 15; Jer 4:2; 16:14). The NT\'s "He is risen!" (<em>ēgerthē</em>, Mark 16:6) is the ultimate enactment of <em>ḥay YHWH</em>: the living God reveals his living nature definitively in the resurrection of his anointed king.</p>',
    "47": '<p>A type: "The God who gives me justice and subdues peoples under me." The divine gift of justice (<em>nōtēn nĕqāmôt</em>, who gives vindication/vengeance) and the subjection of peoples is the royal entitlement that finds its ultimate expression in Christ. Romans 12:19 quotes "Vengeance is mine, says the LORD" as the reason believers should not take revenge — God himself, through Christ, administers the final vindication. The divine justice that vindicates the Davidic king is the justice that vindicates the crucified Messiah in the resurrection.</p>',
    "48": '<p>A type: "Who rescued me from my enemies — you lifted me above those who rose against me, you saved me from the violent man." The divine lifting above the opponents — elevation that transcends the opposition — is the resurrection-and-ascension pattern. Acts 2:33: "Exalted to the right hand of God, he has received from the Father the promised Holy Spirit." The elevation above enemies in Psalm 18 is the Christological pattern of ascension — raised above all who opposed him, seated at the Father\'s right hand.</p>',
    "49": '<p>A direct citation: "Therefore I will give you thanks, O LORD, among the nations, and sing praises to your name." Paul quotes this verse in Romans 15:9 explicitly as a prophecy of Christ\'s Gentile mission: "I will praise you among the Gentiles; I will sing hymns to your name" — citing it as one of four OT texts demonstrating that "Christ has become a servant of the Jews on behalf of God\'s truth to confirm the promises made to the patriarchs so that the Gentiles may glorify God." The praise of YHWH "among the nations" is the Messianic inclusion of the Gentiles in Israel\'s worship.</p>',
    "50": '<p>A direct connection: "He gives great salvation to his king and shows steadfast love to his anointed — to David and his descendants forever." The covenant of eternal ḥesed to the Davidic line reaches its culmination in Christ. Peter at Pentecost (Acts 2:30-31) applies the Davidic covenant to the resurrection: "knowing that God had promised him on oath that he would place one of his descendants on his throne... he spoke of the resurrection of the Messiah." The "descendants forever" of Psalm 18:50 is ultimately the single descendant who lives forever — the risen Christ.</p>',
  },
  "19": {
    "1": '<p>A revelation of God: "The heavens declare the glory of God, and the expanse proclaims his handiwork." The creation\'s witness to the Creator is the foundational claim of general revelation. Paul in Romans 1:20 builds on this: "since the creation of the world God\'s invisible qualities... have been clearly seen, being understood from what has been made, so that people are without excuse." The Christ who is "the exact representation of his being" (Heb 1:3) is the ultimate expression of what the heavens declare — the glory of God made visible in a person.</p>',
    "2": '<p>A revelation of God: "Day after day pours out its speech, and night after night reveals knowledge." The unceasing testimony of creation — day and night without pause — is the continuous revelation that precedes and accompanies the special revelation of Scripture (vv. 7–11) and the ultimate revelation in Christ. John 1:9 ("The true light that gives light to everyone was coming into the world") is the fulfillment of creation\'s light-witness: the light of each day is a shadow of the Light who is Christ.</p>',
    "3": '<p>A revelation of God: "There is no speech, there are no words — their voice cannot be heard." The paradox of creation\'s testimony: it speaks without words, conveys without language. The Word of God (John 1:1-3, 14) who created all things is the one whose creative speech underlies the voiceless testimony of the heavens. The speechless proclamation of creation and the spoken proclamation of the Word-made-flesh are two modes of the same divine self-revelation, reaching their personal fullness in Christ.</p>',
    "4": '<p>A direct citation: "Yet their proclamation goes out through all the earth, and their message to the ends of the world." Paul quotes this verse in Romans 10:18 — "Did they not hear? Of course they did: \'Their voice has gone out into all the earth, their words to the ends of the world.\'" Paul applies the creation-witness of Psalm 19:4 to the apostolic proclamation of the gospel: the universal speech of creation becomes the model for the universal speech of the gospel. Christ as the fulfillment of both creations (first and new) sends preachers who proclaim as broadly as the heavens declare.</p>',
    "5": '<p>A shadow: "Which rises like a bridegroom leaving his chamber, and rejoices like a champion eager to run his course." The sun as a bridegroom and champion is ANE royal imagery applied to creation\'s most powerful visible element. The NT applies the bridegroom image to Christ specifically: Matthew 9:15 ("the guests of the bridegroom cannot mourn while he is with them"); John 3:29 ("The bride belongs to the bridegroom"); Revelation 19:7 ("the wedding of the Lamb has come"). The bridegroom-sun is a shadow of the Bridegroom who is the light of the world (John 8:12).</p>',
    "6": '<p>A shadow: "Its rising is from one end of the heavens, and its circuit reaches the other end; nothing is hidden from its heat." The all-reaching heat of the sun — nothing hidden from it — is the type of the omniscient presence of Christ. Hebrews 4:13 ("Nothing in all creation is hidden from God\'s sight. Everything is uncovered and laid bare before the eyes of him to whom we must give account") and Revelation 1:14 ("his eyes were like blazing fire") show Christ as the one whose searching gaze, like the sun\'s heat, reaches everything.</p>',
    "7": '<p>A type: "The instruction of the LORD is perfect, reviving the soul; the testimony of the LORD is trustworthy, making the simple wise." The Torah\'s life-giving, soul-reviving perfection is fulfilled in Christ who embodies Torah. John 5:39-40: "You study the Scriptures diligently because you think that in them you have eternal life — these are the very Scriptures that testify about me, yet you refuse to come to me to have life." The life that Torah points to is the life that Christ gives. He does not abolish the Torah\'s function; he is its fulfillment (Matt 5:17).</p>',
    "8": '<p>A type: "The precepts of the LORD are right, bringing joy to the heart; the commandment of the LORD is radiant, enlightening the eyes." The Torah\'s joy-producing and eye-opening qualities are what the New Covenant promise in Jeremiah 31:33 reframes: "I will put my law in their minds and write it on their hearts." Christ, through the Spirit, writes the Torah that Psalm 19 praises on the inner person — producing genuine joy and illumination from within, not merely the external commandment.</p>',
    "9": '<p>A type: "The fear of the LORD is pure, enduring forever; the judgments of the LORD are true and altogether righteous." The "fear of the LORD" that endures forever — the covenant disposition that produces wisdom — finds its fullest expression in Christ, who "grew in wisdom" (Luke 2:52) and "feared God" (Heb 5:7: he was heard because of his reverent submission). The eternal endurance of the divine judgments that are "altogether righteous" is grounded in Christ, through whom the final judgment will be righteous (Acts 17:31).</p>',
    "10": '<p>A theme: "They are more desirable than gold... and sweeter than honey, than honey dripping from the comb." The surpassing value of divine instruction — more than gold, sweeter than honey — is the wisdom tradition\'s highest commendation. Christ as the wisdom of God (1 Cor 1:24, 30) is what the Torah\'s wisdom pointed to. The "honey from the comb" sweetness of Psalm 19 is the type of the "good news" (<em>euangelion</em>) — literally, good-tasting message — that Christ brings and embodies.</p>',
    "11": '<p>A theme: "Moreover, your servant is warned by them; in keeping them there is great reward." The Torah\'s function of warning and rewarding the covenant servant anticipates the role of Scripture in the Christian life. 2 Timothy 3:16-17 ("All Scripture is God-breathed and is useful for teaching, rebuking, correcting and training in righteousness") restates Psalm 19\'s logic. The "great reward (<em>ʿēqeb rāb</em>)" of keeping the divine instruction is ultimately the reward of eternal life in Christ (Matt 5:12; 1 Cor 3:14).</p>',
    "12": '<p>A revelation of God: "Who can understand his own errors? Cleanse me from sins I cannot see." The acknowledgment of hidden sins — failures the speaker cannot even perceive — establishes the radical need for divine cleansing beyond self-knowledge. 1 John 1:7-9 ("the blood of Jesus, his Son, purifies us from all sin... if we confess our sins, he is faithful and just and will forgive us our sins and purify us from all unrighteousness") is the answer to Psalm 19:12. The cleansing from hidden sins is one of the functions of Christ\'s atoning work.</p>',
    "13": '<p>A type: "Keep your servant also from willful sins; let them not have mastery over me. Then I will be blameless and clean of great rebellion." The prayer against willful sins and their mastery over the person anticipates the NT\'s theology of sin\'s dominion and the freedom Christ brings. Romans 6:12-14 ("Do not let sin reign in your mortal body... sin shall no longer be your master, because you are not under the law, but under grace") is the answer to the prayer of Psalm 19:13: the freedom from sin\'s mastery is the work of Christ and the Spirit.</p>',
    "14": '<p>A direct connection: "May the words of my mouth and the meditation of my heart be pleasing in your sight, O LORD, my rock and my redeemer." The final title — "my redeemer (<em>gōʾēlî</em>)" — applies the kinsman-redeemer concept to YHWH. The <em>gōʾēl</em> is the nearest male relative who has the right and duty to redeem family members from slavery or poverty (Lev 25:25-28; Ruth 3-4). The NT applies the redeemer concept to Christ throughout: Galatians 3:13 ("Christ redeemed us from the curse of the law"), Titus 2:14 ("who gave himself for us to redeem us from all wickedness"). YHWH as <em>gōʾēl</em> is fulfilled in Christ who becomes kin to redeem humanity.</p>',
  },
  "20": {
    "1": '<p>A type: Psalm 20 is a royal liturgy — the people\'s communal prayer before the king goes to battle. "May the LORD answer you in your day of trouble! May the name of the God of Jacob set you on high!" The community praying for the anointed king\'s victory is the type of the NT community praying for Christ\'s eschatological victory. The "day of trouble (<em>yôm ṣārāh</em>)" is the type of the hour of the Passion — the decisive battle for which the community prays.</p>',
    "2": '<p>A type: "May he send you help from his sanctuary and support you from Zion!" The divine help from the sanctuary sent to the battling king anticipates the Father\'s support of the Son in the Passion. Luke 22:43 ("An angel from heaven appeared to him and strengthened him") is a partial fulfillment — divine help sent from heaven to the one in the decisive battle. The full answer to Psalm 20:2 is the resurrection: help from the heavenly sanctuary that raised the king from death.</p>',
    "3": '<p>A type: "May he remember all your offerings and accept your burnt sacrifices!" The priestly dimension of the royal liturgy — the king\'s offerings accepted by YHWH — is fulfilled in Christ who is simultaneously the priest who offers and the sacrifice offered. Hebrews 9:14 ("how much more will the blood of Christ, who through the eternal Spirit offered himself unblemished to God, cleanse our consciences"). The "accepted sacrifice" of Psalm 20:3 is the type of the one sacrifice that is definitively acceptable.</p>',
    "4": '<p>A type: "May he grant you your heart\'s desire and fulfill all your plans!" The fulfillment of the king\'s desires and plans by YHWH is the covenant entitlement of the anointed. For Christ, this points to the fulfillment of the mission for which he came: John 17:4 ("I have brought you glory on earth by finishing the work you gave me to do"). The "heart\'s desire" of Christ — the redemption of the world, the glorification of the Father — is fulfilled through the cross and resurrection.</p>',
    "5": '<p>A type: "May we shout for joy at your victory, and in the name of our God raise our banners! May the LORD fulfill all your requests!" The community\'s anticipatory joy at the king\'s victory is the type of the NT community\'s celebration of Christ\'s accomplished victory. Revelation 5:12 ("Worthy is the Lamb, who was slain, to receive power and wealth and wisdom and strength and honor and glory and praise!") is the fulfillment of Psalm 20\'s shout of victory — the entire redeemed community celebrating the Messianic king\'s triumph.</p>',
    "6": '<p>A direct connection: "Now I know that the LORD saves his anointed one (<em>mĕšîḥô</em>); he answers him from his holy heaven with the saving power of his right hand." The Messiah term (<em>māšîaḥ</em>) appears here — the first use in a royal psalm of the specific word that will carry the weight of Israel\'s eschatological hopes. "The LORD saves his anointed" is the claim that the resurrection fulfills: God answered the crucified Messiah "from his holy heaven with the saving power of his right hand" — the right hand of God that raised Christ (Acts 2:33-34; Eph 1:20) is the "saving power of his right hand" of Psalm 20:6.</p>',
    "7": '<p>A revelation of God: "Some boast in chariots and some in horses, but we will boast in the name of the LORD our God." The anti-military boast principle — trust in divine power over human weapons — is the OT anticipation of Paul\'s theology of the cross: "For the foolishness of God is wiser than human wisdom, and the weakness of God is stronger than human strength" (1 Cor 1:25). The cross is the ultimate anti-chariot victory: the Messiah wins through what appears to be total defeat, confounding all worldly power calculations.</p>',
    "8": '<p>A theme: "They collapse and fall, but we rise and stand firm." The contrast between the fallers and the standers is the Psalm\'s confident assertion of Messianic victory. Romans 14:4 ("the Lord is able to make them stand") and Romans 8:31 ("If God is for us, who can be against us?") develop the confidence of Psalm 20:8. Those who trust in the Messiah\'s victory stand; those who oppose it collapse. The resurrection is the decisive demonstration that Christ, though he fell in death, stands eternally.</p>',
    "9": '<p>A direct connection: "LORD, give victory to the king! Answer us when we call." The community\'s closing petition for the king and for themselves — "answer us when we call" — is the prayer that the NT community prays through Christ as mediator. 1 Timothy 2:5 ("there is one God and one mediator between God and mankind, the man Christ Jesus"). The "answer us" of Psalm 20:9 is answered through the Messianic king who intercedes for his people and through whom the Father hears all prayer.</p>',
  },
  "21": {
    "1": '<p>A type: "The king rejoices in your strength, LORD, and in your salvation how greatly he exults!" Psalm 21 is the companion to Psalm 20 — the thanksgiving after the battle for which Psalm 20 prayed. The king\'s rejoicing in divine strength after victory is the type of Christ\'s exultation after the resurrection. Hebrews 12:2 ("For the joy set before him he endured the cross, scorning its shame, and sat down at the right hand of the throne of God") speaks of the joy that follows the decisive battle — the same joy the king expresses in Psalm 21.</p>',
    "2": '<p>A type: "You have given him his heart\'s desire and have not withheld what his lips requested." The divine answer to the king\'s prayer — nothing withheld — is the type of Christ\'s prayer being answered in the resurrection. John 17:5 ("And now, Father, glorify me in your presence with the glory I had with you before the world began") is the request; the resurrection and ascension are the answer. The Father withholds nothing from the Son whose prayer is perfectly aligned with the Father\'s will.</p>',
    "3": '<p>A type: "For you meet him with blessings of goodness and set a crown of finest gold upon his head." The coronation blessing — the crown of fine gold placed on the king\'s head — is fulfilled in Christ\'s eschatological coronation. Revelation 14:14 (the Son of Man with "a golden crown on his head") and Hebrews 2:9 ("we see Jesus, who was made lower than the angels for a little while, now crowned with glory and honor because he suffered death") are the NT fulfillment of the golden crown of Psalm 21:3.</p>',
    "4": '<p>A direct connection: "He asked you for life, and you gave it to him — length of days forever and ever." The king\'s prayer for life answered by YHWH is the type of the resurrection. Christ asked for life (Heb 5:7: "he offered up prayers and petitions with fervent cries and tears to the one who could save him from death, and he was heard because of his reverent submission") and received it — not merely prolonged earthly life but "length of days forever and ever" (<em>ʾōrek yāmîm ʿôlām wāʿed</em>). The resurrection is the answer to this prayer: eternal life granted to the one who asked for life through death.</p>',
    "5": '<p>A type: "Through your salvation his glory is great; you have bestowed splendor and majesty upon him." The post-victory glorification of the king is the type of the post-resurrection glorification of Christ. Philippians 2:9-11: "Therefore God exalted him to the highest place and gave him the name that is above every name, that at the name of Jesus every knee should bow... and every tongue acknowledge that Jesus Christ is Lord." The "splendor and majesty (<em>hôd wĕhādār</em>)" bestowed on the king is the glory given to Christ after he "humbled himself by becoming obedient to death" (Phil 2:8).</p>',
    "6": '<p>A direct connection: "For you make him most blessed forever; you fill him with gladness in your presence." Hebrews 12:2 captures this exactly: Christ endured the cross "for the joy set before him" and "sat down at the right hand of the throne of God." The "gladness in your presence (<em>śimḥāh et-pānêkā</em>)" is the eschatological joy that awaits the resurrection. John 17:24 ("Father, I want those you have given me to be with me where I am, and to see my glory that you have given me") shows Christ desiring to bring his community into this same gladness in the Father\'s presence.</p>',
    "7": '<p>A type: "For the king trusts in the LORD, and through the steadfast love of the Most High he will not be shaken." The king\'s trust in YHWH producing unshakeability is the type of Christ\'s perfect and unbroken trust in the Father — even through the passion. Isaiah 50:7-9 (Servant Song 3) shows the same unshakeable trust: "I have set my face like flint... He who vindicates me is near." The king who will not be shaken by opposition because of divine ḥesed is the type of the Messiah whose trust in the Father holds through crucifixion.</p>',
    "8": '<p>A shadow: "Your hand will reach all your enemies; your right hand will seize those who hate you." The divine conquest through the king\'s hand — all enemies seized — is the eschatological judgment imagery. 1 Corinthians 15:25-26: "he must reign until he has put all his enemies under his feet; the last enemy to be destroyed is death." The "hand reaching all enemies" of Psalm 21 is the ongoing campaign of Christ\'s reign that will not end until every enemy is subjected.</p>',
    "9": '<p>A shadow: "You will make them like a burning oven in the time of your anger; the LORD in his wrath will swallow them up, and fire will devour them." The fiery judgment of the king\'s enemies is the eschatological judgment imagery that the NT applies to Christ\'s final return. 2 Thessalonians 1:7-8: "He will punish those who do not know God and do not obey the gospel of our Lord Jesus. They will be punished with everlasting destruction." The burning oven of Psalm 21 and the "flaming fire" of 2 Thessalonians 1 both draw on the divine warrior\'s theophanic fire as judgment.</p>',
    "10": '<p>A shadow: "You will destroy their offspring from the earth and their descendants from among mankind." The complete end of the opposition\'s lineage — the enemies\' dynasty ended — is the type of the final judgment\'s permanence. In the eschatological framework, those who oppose the Messiah have no "descendants" in the age to come — no continuation, no future, no inheritance. Revelation 20:10 ("they will be tormented day and night for ever and ever") is the ultimate end of the enemies\' "lineage."</p>',
    "11": '<p>A shadow: "For they intended evil against you and devised a plot they cannot carry out." The enemies\' evil intentions and failed schemes — they plotted but could not execute — is the type of Acts 4:27-28: "Indeed Herod and Pontius Pilate met together with the Gentiles and the people of Israel in this city to conspire against your holy servant Jesus... They did what your power and will had decided beforehand should happen." The enemy plot against the Messiah was real — and carried out — yet ultimately unable to succeed because the divine plan governed the outcome.</p>',
    "12": '<p>A shadow: "You will put them to flight as you aim your bow at their faces." The divine archer targeting the enemies who opposed the anointed king is the imagery of the divine warrior\'s eschatological judgment. Revelation 6:2 ("a rider on a white horse... given a crown, and he rode out as a conqueror bent on conquest") and 19:11-15 (Christ as the divine warrior) apply the divine-archer imagery of the Royal Psalms to the returning Christ whose conquest is final.</p>',
    "13": '<p>A direct connection: "Rise in your strength, O LORD! We will sing and praise your mighty deeds." The closing invocation — "Rise (<em>rûmāh</em>) in your strength!" — is the community\'s call for YHWH\'s exaltation after the royal victory. This becomes the Christological acclamation of the resurrection: "He has risen (<em>ēgerthē</em>)!" (Mark 16:6). The "rising" of YHWH in the king\'s victory is the type of the divine rising that is the resurrection of Christ — the definitive exaltation of YHWH in human history. "We will sing and praise your mighty deeds" is the response that the community of the risen Messiah enacts in all its worship.</p>',
  }
}

# INTENT: mkt-christ for Psalms 18–21 — the Royal Psalm cluster covering David's great
#   thanksgiving (Ps 18, with direct citation in Rom 15:9 at v49), creation/Torah diptych
#   (Ps 19, with direct citation in Rom 10:18 at v4), the pre-battle royal prayer with the
#   first 'Messiah' usage (Ps 20:6), and the post-victory royal thanksgiving with the
#   resurrection type at Ps 21:4 ('length of days forever and ever').
# CHANGE? If mkt-christ/psalms.json structure changes, update load_comm/save_comm source string.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/psalms.json'));
#   print('18 v49:', d.get('18',{}).get('49','MISSING')[:80])"

def main():
    existing = load_comm('mkt-christ', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-christ', 'psalms', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Psalms mkt-christ: {len(existing)} chapters, {total} verse entries total')
    print('Psalms 18–21 mkt-christ written.')

if __name__ == '__main__':
    main()
